def _to_decimal(value: MoneyLike) -> Decimal:
    if isinstance(value, Decimal):
        return value
    return Decimal(str(value))

def _money(value: MoneyLike) -> Decimal:
    return _to_decimal(value).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

def _calc_cart_total(cart_items: Sequence[Dict[str, Any]]) -> Decimal:
    total = Decimal("0.00")
    for item in cart_items:
        if not isinstance(item, dict):
            raise ValueError("Each cart item must be a dict.")
        if "price" not in item:
            raise ValueError("Cart item missing 'price'.")
        price = _money(item["price"])
        qty = item.get("quantity", 1)
        if qty is None:
            qty = 1
        if not isinstance(qty, int) or qty <= 0:
            raise ValueError("Cart item 'quantity' must be a positive int.")
        total += (price * Decimal(qty))
    return total.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)

def _discount_rate_for_role(role: str) -> Decimal:
    role_norm = (role or "").strip().lower()
    if role_norm == "enterprise":
        return Decimal("0.30")
