def _validate_payment_details(payment_details: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(payment_details, dict):
        raise ValueError("payment_details must be a dict.")
    method = (payment_details.get("method") or "").strip().lower()
    if method not in {"card", "ach", "paypal"}:
        raise ValueError("Unsupported payment method.")
    if method == "card":
        number = (payment_details.get("card_number") or "").replace(" ", "")
        exp_month = payment_details.get("exp_month")
        exp_year = payment_details.get("exp_year")
        cvv = (payment_details.get("cvv") or "")
        if not number.isdigit() or len(number) < 12 or len(number) > 19:
            raise ValueError("Invalid card_number.")
        if not isinstance(exp_month, int) or not (1 <= exp_month <= 12):
            raise ValueError("Invalid exp_month.")
        if not isinstance(exp_year, int) or exp_year < 2000 or exp_year > 2100:
            raise ValueError("Invalid exp_year.")
        if not isinstance(cvv, str) or not cvv.isdigit() or len(cvv) not in (3, 4):
            raise ValueError("Invalid cvv.")
    elif method == "ach":
        routing = (payment_details.get("routing_number") or "").replace(" ", "")
        account = (payment_details.get("account_number") or "").replace(" ", "")
        if not routing.isdigit() or len(routing) != 9:
            raise ValueError("Invalid routing_number.")
        if not account.isdigit() or len(account) < 4 or len(account) > 17:
            raise ValueError("Invalid account_number.")
    elif method == "paypal":
        email = (payment_details.get("email") or "").strip()
        if "@" not in email or "." not in email.split("@")[-1]:
            raise ValueError("Invalid PayPal email.")
    return payment_details

